SourceCode.Declaration:
internal final class ATLCourseExpirationBatch extends RunBaseBatch
{
}

Method.Source:
/// <summary>
/// Executa o job de expiração de cursos.
/// </summary>
public void run()
{
    int counter;

    counter = ATLCourseService::disableExpiredCourses();

    info(strFmt("%1 curso(s) desabilitado(s) por vencimento.", counter));
}

/// <summary>
/// Ponto de entrada do batch.
/// </summary>
public static void main(Args _args)
{
    ATLCourseExpirationBatch batch = new ATLCourseExpirationBatch();

    if (batch.prompt())
    {
        batch.runOperation();
    }
}

/// <summary>
/// Descrição exibida na tela de agendamento do batch.
/// </summary>
public ClassDescription caption()
{
    return "Expiração Automática de Cursos ATL";
}
